package storage

import (
	"bytes"
	"context"
	"fmt"
	"net/http"
	"testing"

	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"

	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/model/common"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/model/storage"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/test/e2e/setup"
	"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/test/helpers"
)

func TestStorageMultipartE2E(t *testing.T) {
	RegisterFailHandler(Fail)
	RunSpecs(t, "Storage Multipart Upload E2E Tests")
}

var _ = Describe("Storage Multipart Upload E2E Tests", func() {
	var (
		testServer *setup.TestServer
		httpHelper *helpers.HTTPTestHelper
	)

	BeforeEach(func() {
		var err error
		ctx := context.Background()

		// 创建测试服务器（使用 LocalStack）
		testServer, err = setup.NewTestServer(ctx, setup.WithLocalStack("test-bucket"))
		Expect(err).NotTo(HaveOccurred())
		Expect(testServer).NotTo(BeNil())

		// 获取 HTTP 辅助工具
		httpHelper = testServer.GetHTTPHelper()
	})

	AfterEach(func() {
		// 关闭测试服务器
		if testServer != nil {
			_ = testServer.Shutdown(context.Background())
		}
		// 注意：S3 数据清理可以通过脚本完成: ./scripts/localstack.sh cleanup
	})

	Describe("分片上传完整流程", func() {
		It("应该成功完成分片上传", func() {

			// 准备测试数据
			// 注意：S3 要求除最后一个分片外，每个分片至少 5MB
			testKey := helpers.GenerateTestKey("test", "large-file.zip")
			testContentType := "application/zip"
			testData := helpers.GenerateRandomBytes(12 * 1024 * 1024)       // 12MB 测试数据
			testParts := helpers.SplitBytesIntoParts(testData, 5*1024*1024) // 分成 5MB 的分片（符合 S3 要求）

			// 1. 初始化分片上传
			initReq := storage.InitMultipartUploadRequest{
				Key:         testKey,
				ContentType: testContentType,
			}

			initResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/init", initReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResp.StatusCode).To(Equal(http.StatusOK))

			var initResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(initResp, &initResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResult["code"]).To(Equal(common.CodeSuccess), "API should return success, got: %v", initResult)

			// 安全地获取 uploadID
			data, ok := initResult["respBody"].(map[string]interface{})
			Expect(ok).To(BeTrue(), "data field should be a map, got: %v", initResult["respBody"])
			uploadID, ok := data["uploadId"].(string)
			Expect(ok).To(BeTrue(), "uploadId should be a string")
			Expect(uploadID).NotTo(BeEmpty())

			// 2. 上传多个分片
			for i, partData := range testParts {
				partNumber := i + 1

				// 上传分片（使用 FormData）
				uploadResp, err := httpHelper.PostMultipart(
					"/api/v1/storage/multipart/upload",
					map[string]string{
						"key":        testKey,
						"uploadId":   uploadID,
						"partNumber": fmt.Sprintf("%d", partNumber),
					},
					"file",
					bytes.NewReader(partData),
				)
				Expect(err).NotTo(HaveOccurred())
				Expect(uploadResp.StatusCode).To(Equal(http.StatusOK))

				var uploadResult map[string]interface{}
				err = httpHelper.ParseJSONResponse(uploadResp, &uploadResult)
				Expect(err).NotTo(HaveOccurred())
				Expect(uploadResult["code"]).To(Equal(common.CodeSuccess), "Upload part should succeed, got: %v", uploadResult)

				// 安全地获取 etag
				uploadData, ok := uploadResult["respBody"].(map[string]interface{})
				Expect(ok).To(BeTrue(), "data field should be a map, got: %v", uploadResult["respBody"])
				etag, ok := uploadData["etag"].(string)
				Expect(ok).To(BeTrue(), "etag should be a string")
				Expect(etag).NotTo(BeEmpty())
			}

			// 3. 完成分片上传
			completeReq := storage.CompleteMultipartUploadRequest{
				Key:      testKey,
				UploadID: uploadID,
			}

			completeResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/complete", completeReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(completeResp.StatusCode).To(Equal(http.StatusOK))

			var completeResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(completeResp, &completeResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(completeResult["code"]).To(Equal(common.CodeSuccess), "Complete upload should succeed, got: %v", completeResult)

			// 安全地获取 key
			completeData, ok := completeResult["respBody"].(map[string]interface{})
			Expect(ok).To(BeTrue(), "data field should be a map, got: %v", completeResult["respBody"])
			key, ok := completeData["key"].(string)
			Expect(ok).To(BeTrue(), "key should be a string")
			Expect(key).To(Equal(testKey))

			// 4. 验证文件已上传到 S3（可以通过脚本验证: ./scripts/localstack.sh verify <bucket> <key>）
			// 这里简化处理，只验证 API 返回成功
		})

		It("应该支持大文件分片上传", func() {
			// 准备更大的测试数据（10MB）
			testKey := helpers.GenerateTestKey("test", "very-large-file.bin")
			testContentType := "application/octet-stream"
			testData := helpers.GenerateRandomBytes(10 * 1024 * 1024)     // 10MB
			testParts := helpers.SplitBytesIntoParts(testData, 1024*1024) // 分成 1MB 的分片

			// 初始化分片上传
			initReq := storage.InitMultipartUploadRequest{
				Key:         testKey,
				ContentType: testContentType,
			}

			initResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/init", initReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResp.StatusCode).To(Equal(http.StatusOK))

			var initResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(initResp, &initResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResult["code"]).To(Equal(common.CodeSuccess), "Init should succeed, got: %v", initResult)

			// 安全地获取 uploadID
			data, ok := initResult["respBody"].(map[string]interface{})
			Expect(ok).To(BeTrue(), "data field should be a map, got: %v", initResult["respBody"])
			uploadID, ok := data["uploadId"].(string)
			Expect(ok).To(BeTrue(), "uploadId should be a string")

			// 上传所有分片
			for i, partData := range testParts {
				partNumber := i + 1

				uploadResp, err := httpHelper.PostMultipart(
					"/api/v1/storage/multipart/upload",
					map[string]string{
						"key":        testKey,
						"uploadId":   uploadID,
						"partNumber": fmt.Sprintf("%d", partNumber),
					},
					"file",
					bytes.NewReader(partData),
				)
				Expect(err).NotTo(HaveOccurred())
				Expect(uploadResp.StatusCode).To(Equal(http.StatusOK))
				uploadResp.Body.Close()
			}

			// 完成上传
			completeReq := storage.CompleteMultipartUploadRequest{
				Key:      testKey,
				UploadID: uploadID,
			}

			completeResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/complete", completeReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(completeResp.StatusCode).To(Equal(http.StatusOK))
			completeResp.Body.Close()

			// 验证文件（可以通过脚本验证: ./scripts/localstack.sh verify <bucket> <key>）
			// 这里简化处理，只验证 API 返回成功
		})
	})

	Describe("取消分片上传", func() {
		It("应该成功取消正在进行的分片上传", func() {
			testKey := helpers.GenerateTestKey("test", "canceled-file.zip")
			testContentType := "application/zip"
			testData := helpers.GenerateRandomBytes(6 * 1024 * 1024)        // 6MB（至少一个完整分片）
			testParts := helpers.SplitBytesIntoParts(testData, 5*1024*1024) // 分成 5MB 的分片

			// 1. 初始化分片上传
			initReq := storage.InitMultipartUploadRequest{
				Key:         testKey,
				ContentType: testContentType,
			}

			initResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/init", initReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResp.StatusCode).To(Equal(http.StatusOK))

			var initResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(initResp, &initResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResult["code"]).To(Equal(common.CodeSuccess), "Init should succeed, got: %v", initResult)

			// 安全地获取 uploadID
			data, ok := initResult["respBody"].(map[string]interface{})
			Expect(ok).To(BeTrue(), "data field should be a map, got: %v", initResult["respBody"])
			uploadID, ok := data["uploadId"].(string)
			Expect(ok).To(BeTrue(), "uploadId should be a string")

			// 2. 上传第一个分片
			partNumber := 1
			uploadResp, err := httpHelper.PostMultipart(
				"/api/v1/storage/multipart/upload",
				map[string]string{
					"key":        testKey,
					"uploadId":   uploadID,
					"partNumber": fmt.Sprintf("%d", partNumber),
				},
				"file",
				bytes.NewReader(testParts[0]),
			)
			Expect(err).NotTo(HaveOccurred())
			Expect(uploadResp.StatusCode).To(Equal(http.StatusOK))
			uploadResp.Body.Close()

			// 3. 取消分片上传
			abortReq := storage.AbortMultipartUploadRequest{
				Key:      testKey,
				UploadID: uploadID,
			}

			abortResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/abort", abortReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(abortResp.StatusCode).To(Equal(http.StatusOK))

			var abortResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(abortResp, &abortResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(abortResult["code"]).To(Equal(common.CodeSuccess))

			// 4. 验证取消后无法完成上传
			completeReq := storage.CompleteMultipartUploadRequest{
				Key:      testKey,
				UploadID: uploadID,
			}

			completeResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/complete", completeReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(completeResp.StatusCode).To(Equal(http.StatusOK))

			var completeResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(completeResp, &completeResult)
			Expect(err).NotTo(HaveOccurred())
			// 应该返回错误（uploadID 已被清理）
			Expect(completeResult["code"]).To(Equal(common.CodeInternalErr))
		})
	})

	Describe("错误场景", func() {
		It("应该处理无效的上传ID", func() {
			testKey := helpers.GenerateTestKey("test", "invalid-upload-id.zip")

			testData := helpers.GenerateRandomBytes(1024)
			uploadResp, err := httpHelper.PostMultipart(
				"/api/v1/storage/multipart/upload",
				map[string]string{
					"key":        testKey,
					"uploadId":   "invalid-upload-id",
					"partNumber": "1",
				},
				"file",
				bytes.NewReader(testData),
			)
			Expect(err).NotTo(HaveOccurred())
			Expect(uploadResp.StatusCode).To(Equal(http.StatusOK))

			var errorResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(uploadResp, &errorResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(errorResult["code"]).To(Equal(common.CodeInternalErr))
			Expect(errorResult["msg"]).To(ContainSubstring("uploadID not found"))
		})

		It("应该处理完成上传时没有分片的情况", func() {
			testKey := helpers.GenerateTestKey("test", "no-parts.zip")
			testContentType := "application/zip"

			// 初始化分片上传
			initReq := storage.InitMultipartUploadRequest{
				Key:         testKey,
				ContentType: testContentType,
			}

			initResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/init", initReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResp.StatusCode).To(Equal(http.StatusOK))

			var initResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(initResp, &initResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResult["code"]).To(Equal(common.CodeSuccess), "Init should succeed, got: %v", initResult)

			// 安全地获取 uploadID
			data, ok := initResult["respBody"].(map[string]interface{})
			Expect(ok).To(BeTrue(), "data field should be a map, got: %v", initResult["respBody"])
			uploadID, ok := data["uploadId"].(string)
			Expect(ok).To(BeTrue(), "uploadId should be a string")

			// 直接尝试完成上传（没有上传任何分片）
			completeReq := storage.CompleteMultipartUploadRequest{
				Key:      testKey,
				UploadID: uploadID,
			}

			completeResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/complete", completeReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(completeResp.StatusCode).To(Equal(http.StatusOK))

			var errorResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(completeResp, &errorResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(errorResult["code"]).To(Equal(common.CodeInternalErr))
			Expect(errorResult["msg"]).To(ContainSubstring("no parts found"))
		})
	})
})

