// TestServer E2E 测试服务器
type TestServer struct {
	Server     *httptest.Server
	Router     *gin.Engine
	Config     *config.Config
	Logger     *zap.Logger
	TDSCClient tdsc.Client // 可选，用于需要 TDSC 的测试
}

// TestServerOption 测试服务器配置选项
type TestServerOption func(*TestServerConfig)

type TestServerConfig struct {
	UseLocalStack bool
	Bucket        string
	UseTDSC       bool
	TDSCURL       string
}

// WithLocalStack 启用 LocalStack（S3）
func WithLocalStack(bucket string) TestServerOption {
	return func(cfg *TestServerConfig) {
		cfg.UseLocalStack = true
		cfg.Bucket = bucket
	}
}

// WithTDSC 启用 TDSC（可选）
func WithTDSC(url string) TestServerOption {
	return func(cfg *TestServerConfig) {
		cfg.UseTDSC = true
		cfg.TDSCURL = url
	}
}

// NewTestServer 创建测试服务器
func NewTestServer(ctx context.Context, opts ...TestServerOption) (*TestServer, error) {
	cfg := &TestServerConfig{
		Bucket: "test-bucket",
	}
	for _, opt := range opts {
		opt(cfg)
	}

	// 初始化日志
	logger, err := zap.NewDevelopment()
	if err != nil {
		return nil, fmt.Errorf("failed to create logger: %w", err)
	}

	// 创建测试配置
	testConfig := &config.Config{
		Server: config.ServerConfig{
			Mode: "test",
		},
		Log: config.LogConfig{
			Level:      "debug",
			OutputPath: "stdout",
		},
		Auth: config.AuthConfig{
			Enabled:   false, // 测试环境禁用认证
			AuthType:  "jwt",
			JWTSecret: "test-secret",
			TokenTTL:  3600,
		},
		K8s: config.K8sConfig{
			Namespace: "test",
		},
	}

	// 配置 LocalStack（LocalStack 应该已经通过脚本启动）
	// 注意：运行测试前需要先执行: ./scripts/localstack.sh create
	// bucket 会在脚本中自动创建
	if cfg.UseLocalStack {
		testConfig.S3 = config.S3Config{
			Endpoint:  "http://localhost:4566", // LocalStack 默认地址
			AccessKey: "test",
			SecretKey: "test",
			Bucket:    cfg.Bucket,
			Region:    "us-east-1",
		}
	}

	// 配置 TDSC（如果需要）
	var tdscClient tdsc.Client
	if cfg.UseTDSC {
		testConfig.TDSC = config.TDSCConfig{
			URL: cfg.TDSCURL,
			Vol: "test-vol",
		}
		// 注意：这里不初始化真实的 TDSC 客户端，因为 E2E 测试可能不需要真实的 TDSC
		// 如果需要，可以在这里初始化
	}

	// 创建认证服务
	authService := auth.NewService(testConfig.Auth, zap.NewNop())

	// 创建认证中间件
	authMiddleware := middleware.NewAuthMiddleware(authService, &testConfig.Auth)

	// 创建 Gin 引擎
	gin.SetMode(gin.TestMode)
	router := gin.New()
	router.Use(gin.Recovery())

	// 注册路由
	handler.RegisterRoutes(router, authMiddleware, authService, logger, testConfig)

	// 创建测试服务器
	server := httptest.NewServer(router)

	return &TestServer{
		Server:     server,
		Router:     router,
		Config:     testConfig,
		Logger:     logger,
		TDSCClient: tdscClient,
	}, nil
}

// Shutdown 关闭测试服务器
func (s *TestServer) Shutdown(ctx context.Context) error {
	if s.Server != nil {
