			// 1. 初始化分片上传
			initReq := storage.InitMultipartUploadRequest{
				Key:         testKey,
				ContentType: testContentType,
			}

			initResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/init", initReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResp.StatusCode).To(Equal(http.StatusOK))

			var initResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(initResp, &initResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(initResult["code"]).To(Equal(common.CodeSuccess), "Init should succeed, got: %v", initResult)

			// 安全地获取 uploadID
			data, ok := initResult["respBody"].(map[string]interface{})
			Expect(ok).To(BeTrue(), "data field should be a map, got: %v", initResult["respBody"])
			uploadID, ok := data["uploadId"].(string)
			Expect(ok).To(BeTrue(), "uploadId should be a string")

			// 2. 上传第一个分片
			partNumber := 1
			uploadResp, err := httpHelper.PostMultipart(
				"/api/v1/storage/multipart/upload",
				map[string]string{
					"key":        testKey,
					"uploadId":   uploadID,
					"partNumber": fmt.Sprintf("%d", partNumber),
				},
				"file",
				bytes.NewReader(testParts[0]),
			)
			Expect(err).NotTo(HaveOccurred())
			Expect(uploadResp.StatusCode).To(Equal(http.StatusOK))
			uploadResp.Body.Close()

			// 3. 取消分片上传
			abortReq := storage.AbortMultipartUploadRequest{
				Key:      testKey,
				UploadID: uploadID,
			}

			abortResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/abort", abortReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(abortResp.StatusCode).To(Equal(http.StatusOK))

			var abortResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(abortResp, &abortResult)
			Expect(err).NotTo(HaveOccurred())
			Expect(abortResult["code"]).To(Equal(common.CodeSuccess))

			// 4. 验证取消后无法完成上传
			completeReq := storage.CompleteMultipartUploadRequest{
				Key:      testKey,
				UploadID: uploadID,
			}

			completeResp, err := httpHelper.PostJSON("/api/v1/storage/multipart/complete", completeReq)
			Expect(err).NotTo(HaveOccurred())
			Expect(completeResp.StatusCode).To(Equal(http.StatusOK))

			var completeResult map[string]interface{}
			err = httpHelper.ParseJSONResponse(completeResp, &completeResult)
			Expect(err).NotTo(HaveOccurred())
			// 应该返回错误（uploadID 已被清理）
			Expect(completeResult["code"]).To(Equal(common.CodeInternalErr))
		})
	})

	Describe("错误场景", func() {
		It("应该处理无效的上传ID", func() {
			testKey := helpers.GenerateTestKey("test", "invalid-upload-id.zip")

			testData := helpers.GenerateRandomBytes(1024)
